    private static int countEvenPairsInCircularArray(int[] arr){
        int n = arr.length;
        if(arr.length < 2 ) return 0;

        if(arr.length == 2 ){
            if((arr[0] + arr[1])%2 == 0){
                return 1;
            }else{
                return 0;
            }
        }
        boolean zeroIndexTaken = false;

        int[] answer = new int[n];

        if((arr[0]+arr[1])%2 == 0){
            answer[0] = 1;
        }

        if((arr[1]+arr[2])%2 == 0){
            answer[1] = 1;
        }

        for(int i = 2; i < n-1; i++){
            answer[i] = (arr[i]+arr[i+1])%2 == 0 ? answer[i-2] + 1: answer[i-2]; 
        }

        if((arr[1]+arr[0])%2 == 0){
            answer[n-1] =  answer[n-3];
        }else{
            answer[n-1] =  answer[n-1]+answer[0] == 0 ? answer[n-3] + 1: answer[n-3];
        }

        return Math.max(answer[n-1], answer[n-2]);

    }
